questions.extend(extra)

# Keep options in authored order; app will shuffle choices on display.
# Give stable IDs.
for i, q in enumerate(questions, 1):
    q['id'] = f"GH900-{i:03d}"

out_dir = "/mnt/data/gh900-quiz"
os.makedirs(out_dir, exist_ok=True)
with open(os.path.join(out_dir, "questions.js"), "w", encoding="utf-8") as f:
    f.write("// Original GH-900 practice questions aligned to the Microsoft Learn study guide. Not real exam dumps.\n")
    f.write("const QUESTIONS = ")
    json.dump(questions, f, ensure_ascii=False, indent=2)
    f.write(";\n")
print(len(questions))
